    int rowCost = 0, colCost = 0;
    for (int i = 0; i < rowDifference; i++)
        rowCost += rowCosts[i + Math.min(startPos[0], homePos[0])];
    for (int i = 0; i < colDifference; i++)
        colCost += colCosts[i + Math.min(startPos[1], homePos[1])];

    return rowCost + colCost;
}
```

